import React from 'react';
import { useStaticQuery, graphql } from 'gatsby';
import Layout from '../../components/layout';
import SectionMenu from '../../components/sections/menu';
import Thumbnails from '../../components/thumbnails';

const WorksPage = () => {
  const worksThumbnails = useStaticQuery(graphql`
    {
      allFile(filter: { relativeDirectory: { eq: "works-thumbnails" } }) {
        edges {
          node {
            childImageSharp {
              gatsbyImageData(width: 400)
            }
            name
          }
        }
      }
    }
  `);

  const get = (name, link) => {
    if (!link) {
      const [, _link] = name.match(/^portfolio_works_(.+)_00$/);
      link = _link.replace(/_/g, '-');
    }

    const [{ node }] = worksThumbnails.allFile.edges.filter(
      worksThumbnail => worksThumbnail.node.name === name
    );

    return {
      name: node?.name,
      image: node?.childImageSharp?.gatsbyImageData,
      link
    };
  };

  const datas = [
    get('portfolio_works_20230104_interior-2_00'),
    get('portfolio_works_20230104_interior-1_00'),
    get('portfolio_works_20230103_interior-1_00'),
    get('portfolio_works_20230101_interior-1_00'),
    get('portfolio_works_20221201_portrait-1_00'),
    get('portfolio_works_20221105_wosaka-7_00'),
    get('portfolio_works_20221105_wosaka-6_00'),
    get('portfolio_works_20221105_wosaka-5_00'),
    get('portfolio_works_20221105_wosaka-4_00'),
    get('portfolio_works_20221105_wosaka-3_00'),
    get('portfolio_works_20221105_wosaka-2_00'),
    get('portfolio_works_20221105_wosaka-1_00'),
    get('portfolio_works_20221030_streetsnap-1_00'),
    get('portfolio_works_20221020_portrait-1_00'),
    get('portfolio_works_20221010_ritzokinawa-1_00'),
    get('portfolio_works_20220910_hotelthemitsuikyoto-1_00'),
    get('portfolio_works_20220826_stregisosaka-3_00'),
    get('portfolio_works_20220826_stregisosaka-2_00'),
    get('portfolio_works_20220826_stregisosaka-1_00'),
    get('portfolio_works_20220814_thetokyoeditiontoranomon-4_00'),
    get('portfolio_works_20220814_thetokyoeditiontoranomon-3_00'),
    get('portfolio_works_20220814_thetokyoeditiontoranomon-2_00'),
    get('portfolio_works_20220814_thetokyoeditiontoranomon-1_00'),
    get('portfolio_works_20220512_interior-1_00'),
    get('portfolio_works_20210824_interior-1_00'),
    get('portfolio_works_20210614_interior-1_00'),
    get('portfolio_works_20201030_streetsnap-1_00')
  ];

  return (
    <Layout>
      <SectionMenu />
      <Thumbnails datas={datas} />
    </Layout>
  );
};

export default WorksPage;
